
figma.showUI('<script>window.onload=()=>{parent.postMessage({pluginMessage:{type:"create"}}, "*")}</script>', { visible: false });

const B64 = "";

figma.ui.onmessage = async (msg) => {
  if (msg.type === "create") {
    const bytes = Uint8Array.from(atob(B64), c => c.charCodeAt(0));
    const imageHash = figma.createImage(bytes).hash;
    const frame = figma.createFrame();
    frame.name = "Homepage Screenshot";
    frame.resize(1440, 900);
    frame.fills = [{ type: "IMAGE", imageHash, scaleMode: "FILL" }];
    figma.currentPage.appendChild(frame);
    figma.viewport.scrollAndZoomIntoView([frame]);
    figma.closePlugin("Homepage importada com sucesso!");
  }
};
